// Images
import ratedR from "../assets/rated-r.png";
import ratedPG13 from "../assets/rated-pg-13.png";
import ratedPG from "../assets/rated-pg.png";
import ratedG from "../assets/rated-g.png";


const MovieCard = ({ title, rating, release, genre, runtime, poster, writer, director, myRating }) => {

    function ratingSrc(rating) {
        if (rating === "R") {
            return String(ratedR)
        } else if (rating === "PG-13") {
            return String(ratedPG13)
        } else if (rating === "PG") {
            return String(ratedPG)
        } else {
            return String(ratedG)
        }
    }

    const releaseYear = new Date(release)

    const renderGenre = genre.map(genre => {
        return (
            <span className="me-2 mb-2 inline-flex items-center px-3 py-2 text-xs font-medium text-center text-white bg-sky-700 rounded-lg">{genre.genre1}</span>

        )
    })

    return (
        <div className="basis-1/5">
            <div className="bg-white rounded-lg shadow m-2">
                <a href="#">
                    <img className="rounded-t-lg" src={poster} alt={title} />
                </a>
                <div className="p-5">
                    <a href="#">
                        <h5 className="text-2xl font-bold tracking-tight text-black">{title}</h5>
                        <p className="inline font-normal text-gray-700">({releaseYear.getFullYear()})</p>
                    </a>
                    <div className="mt-2 flex">
                        <img className="me-1 mb-1 h-5" src={ratingSrc(rating)} />
                        <p className="me-1 font-normal text-gray-700">{runtime} min</p>
                    </div>
                    <div className="mt-2">
                        {[...Array(myRating)].map((star) => {
                            return (
                                <span className="text-yellow-500">&#9733;</span>
                            )
                        })}
                        </div>
                    <div className="mt-2">
                        <p className="font-normal text-sm text-gray-700">{writer}, writer</p>
                        <p className="font-normal text-sm text-gray-700">{director}, director</p>
                    </div>
                    <div className="mt-2">
                        <span className="me-2  mb-2 inline-flex items-center px-3 py-2 text-xs font-medium text-center text-white bg-sky-700 rounded-lg">{genre.genre2}</span>
                        <span className="inline-flex items-center px-3 py-2 text-xs font-medium text-center text-white bg-sky-700 rounded-lg">{genre.genre3}</span>
                    </div>
                </div>
            </div>
        </div>
    )
}

export default MovieCard;
